    "glossary.json": {
  "terms": [
    {
      "term": "고급 표현식 (Advanced Expression)",
      "definition": "선택 항목, 연산자 및 함수를 포함하는 표현식입니다. 부품 및 부품 사용 링크에 할당하여 구성 요소가 제품 구조에 포함되어야 하는 조건을 지정할 수 있습니다."
    },
    {
      "term": "기본 표현식 (Basic Expression)",
      "definition": "부품 및 부품 사용 링크에 할당할 수 있는 옵션 선택 항목으로, 구성 요소가 제품 구조에 포함되어야 하는 조건을 지정합니다."
    },
    {
      "term": "구성 가능 모듈 (Configurable Module)",
      "definition": "구성 요소 또는 기능 단위의 설계 및 구성 변형을 나타내는 하나 이상의 하위 부품을 가질 수 있는 Windchill 부품입니다."
    },
    {
      "term": "구성 가능 제품 (Configurable Product)",
      "definition": "제품 변형의 모음을 나타내는 최상위 완제품입니다. 예를 들어, 일부 표준 구성 요소를 공유하는 다양한 모델이 있는 제품 패밀리가 있습니다."
    },
    {
      "term": "구성 가능 제품 구조 (Configurable Product Structure)",
      "definition": "동일한 제품 구조에서 여러 제품 변형을 생성하는 기능을 지원하기 위해 구성 가능 모듈을 포함합니다."
    },
    {
      "term": "조건부 규칙 (Conditional Rule)",
      "definition": "IF/THEN 문을 사용하여 옵션 필터에서 다른 선택 항목 선택에 따라 특정 옵션 선택 항목이 포함, 활성화 또는 비활성화되어야 하는 시기를 지정하는 규칙입니다."
    },
    {
      "term": "활성화 규칙 (Enable Rule)",
      "definition": "특정 대상 선택 항목이 선택되면 특정 선택 항목만 선택 가능하도록 표시하는 규칙입니다."
    },
    {
      "term": "제외 규칙 (Exclude Rule)",
      "definition": "호환되지 않는 선택 항목의 선택을 제한하는 규칙입니다. 예를 들어, 110볼트를 선택하면 50Hz 주파수를 선택할 수 없습니다."
    },
    {
      "term": "표현식 별칭 (Expression Alias)",
      "definition": "조건부 규칙, 고급 표현식 및 기타 별칭을 작성할 때 재사용할 수 있는 명명된 논리문입니다. 글로벌 제품 관리를 위한 공통 정의를 포착합니다."
    },
    {
      "term": "포함 규칙 (Include Rule)",
      "definition": "하나의 옵션 선택 항목 선택을 하나 이상의 관련 옵션 선택 항목과 연결하는 규칙입니다. 소스 선택 항목을 선택하면 대상 선택 항목이 자동으로 선택됩니다."
    },
    {
      "term": "모듈 변형 (Module Variant)",
      "definition": "변형 생성 시 선택 기준 및 선택 항목 할당에 따라 구성 가능 모듈의 선택적 부품 및 구성 요소에서 선택된 특정 부품입니다."
    },
    {
      "term": "옵션 (Option)",
      "definition": "특정 제품 기능입니다. 옵션에는 하나 이상의 선택 항목이 있으며, 필수 또는 단일 선택으로 설정할 수 있고, 특정 제품 변형에 적용할 수 있습니다."
    },
    {
      "term": "옵션 필터 (Option Filter)",
      "definition": "부품에 할당된 선택 항목과 구조 내 부품 사용에 따라 제품 구조를 필터링하는 데 사용되는 기준 세트입니다."
    },
    {
      "term": "옵션 관리자 (Option Manager)",
      "definition": "옵션과 선택 항목을 생성하고 옵션 세트 및 기타 관련 정보를 유지 관리하는 권한을 가진 Windchill 컨텍스트 역할입니다."
    },
    {
      "term": "옵션 풀 (Option Pool)",
      "definition": "제품에 사용할 수 있는 모든 옵션과 해당 선택 항목을 보유하는 컨테이너입니다. 옵션과 선택 항목은 옵션 풀 내에서 관리됩니다."
    },
    {
      "term": "옵션 세트 (Option Set)",
      "definition": "하나 이상의 옵션 풀에서 가져온 옵션과 선택 항목의 하위 집합으로, 제품 패밀리 내의 변형을 정의하는 데 사용됩니다. 옵션 세트는 변경 관리 객체입니다."
    },
    {
      "term": "매개변수 (Parameter)",
      "definition": "부품 구성 프로세스 중 고급 선택 논리를 지원하기 위해 구성 가능 모듈의 컨텍스트 내에서 로컬로 정의되는 속성입니다."
    },
    {
      "term": "제품 패밀리 (Product Family)",
      "definition": "다양한 기능을 제공하며 상당한 비율의 동일 부품을 공유하는 관련 제품의 집합입니다."
    },
    {
      "term": "변형 (Variant)",
      "definition": "구성 프로세스 중에 생성되는 구성 가능 제품 구조의 특정 구성을 나타내는 부품 또는 부품 구조입니다."
    },
    {
      "term": "변형 사양 (Variant Specification)",
      "definition": "구성 프로세스 중에 제공된 사용자의 옵션 선택 항목 및 매개변수 값 입력 기록으로, 변형 부품 구조를 생성하는 데 사용됩니다."
    },
    {
      "term": "구성 가능 모듈 지원 (Configurable Module Support)",
      "definition": "선택적 제품 구조를 생성하는 기능을 제어하는 Windchill 환경 설정입니다. 옵션 및 변형 기능을 사용하려면 '예'로 설정해야 합니다."
    }
  ]
},
